def gen(rng, size):
    n = max(2, size)
    online = [True] * n
    for i in range(1, n - 1):
        if rng.random() < 0.25:
            online[i] = False
    edges = []
    for u in range(n):
        for v in range(u + 1, n):
            if rng.random() < 0.5:
                edges.append([u, v, rng.randrange(0, 20)])
    k = rng.randrange(0, 60)
    return [edges, online, k]

