class Solution:
    def findMaxPathScore(self, edges, online, k):
        from collections import defaultdict
        n = len(online)
        g = defaultdict(list)
        for u, v, c in edges:
            g[u].append((v, c))
        best = [-1]
        def usable(node):
            return node == 0 or node == n - 1 or online[node]
        def dfs(u, total, mn):
            if total > k:
                return
            if u == n - 1:
                if mn > best[0]:
                    best[0] = mn
                return
            for v, c in g[u]:
                if not usable(v):
                    continue
                nm = c if mn is None else min(mn, c)
                dfs(v, total + c, nm)
        if usable(0):
            dfs(0, 0, None)
        return best[0]

