class Solution:
    def findMaxPathScore(self, edges, online, k):
        import heapq
        n = len(online)
        def usable(node):
            return node == 0 or node == n - 1 or online[node]
        adj = [[] for _ in range(n)]
        costs = set()
        for u, v, c in edges:
            adj[u].append((v, c))
            costs.add(c)
        def feasible(x):
            INF = float('inf')
            dist = [INF] * n
            dist[0] = 0
            pq = [(0, 0)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                if u == n - 1:
                    return d <= k
                for v, c in adj[u]:
                    if c < x or not usable(v):
                        continue
                    nd = d + c
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            return dist[n - 1] <= k
        if not feasible(0):
            return -1
        cand = sorted(costs)
        lo, hi = 0, len(cand) - 1
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(cand[mid]):
                ans = cand[mid]
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

