var findMaxPathScore = function(edges, online, k) {
    k = BigInt(k);
    const n = online.length;
    const usable = (node) => node === 0 || node === n - 1 || online[node];
    const adj = Array.from({ length: n }, () => []);
    const costSet = new Set();
    for (const [u, v, c] of edges) { adj[u].push([v, c]); costSet.add(c); }
    const feasible = (x) => {
        const INF = Infinity;
        const dist = new Array(n).fill(INF);
        dist[0] = 0;
        const pq = [[0n, 0]];
        const push = (it) => { pq.push(it); let i = pq.length - 1; while (i > 0) { const p = (i - 1) >> 1; if (pq[p][0] <= pq[i][0]) break; [pq[p], pq[i]] = [pq[i], pq[p]]; i = p; } };
        const pop = () => { const top = pq[0], last = pq.pop(); if (pq.length) { pq[0] = last; let i = 0; const m = pq.length; while (true) { let l = 2*i+1, r = 2*i+2, s = i; if (l < m && pq[l][0] < pq[s][0]) s = l; if (r < m && pq[r][0] < pq[s][0]) s = r; if (s === i) break; [pq[s], pq[i]] = [pq[i], pq[s]]; i = s; } } return top; };
        const dd = new Array(n).fill(null);
        dd[0] = 0n;
        while (pq.length) {
            const [d, u] = pop();
            if (dd[u] !== null && d > dd[u]) continue;
            if (u === n - 1) return d <= k;
            for (const [v, c] of adj[u]) {
                if (c < x || !usable(v)) continue;
                const nd = d + BigInt(c);
                if (dd[v] === null || nd < dd[v]) { dd[v] = nd; push([nd, v]); }
            }
        }
        return dd[n - 1] !== null && dd[n - 1] <= k;
    };
    if (!feasible(0)) return -1;
    const cand = [...costSet].sort((a, b) => a - b);
    let lo = 0, hi = cand.length - 1, ans = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (feasible(cand[mid])) { ans = cand[mid]; lo = mid + 1; } else { hi = mid - 1; }
    }
    return ans;
};
